# Terraform — Route 53 latency routing records
resource "aws_route53_record" "llm_us" {
  zone_id        = var.zone_id
  name           = "api.example.com"
  type           = "A"
  set_identifier = "us-east-1"

  latency_routing_policy {
    region = "us-east-1"
  }

  alias {
    name                   = aws_lb.us.dns_name
    zone_id                = aws_lb.us.zone_id
    evaluate_target_health = true   # automatic failover if health check fails
  }
}

resource "aws_route53_record" "llm_eu" {
  zone_id        = var.zone_id
  name           = "api.example.com"
  type           = "A"
  set_identifier = "eu-west-1"

  latency_routing_policy {
    region = "eu-west-1"
  }

  alias {
    name                   = aws_lb.eu.dns_name
    zone_id                = aws_lb.eu.zone_id
    evaluate_target_health = true
  }
}

// Cloudflare Worker — route to nearest vLLM cluster
export default {
  async fetch(request, env) {
    const region = request.cf.region;  // e.g. "EEUR", "NAEAST"
    const backend = regionToBackend(region);

    const upstream = new Request(
      `https://${backend}/v1/chat/completions`,
      request
    );
    return fetch(upstream);
  }
};

function regionToBackend(cf_region) {
  if (cf_region?.startsWith("EU")) return env.EU_BACKEND;
  if (cf_region?.startsWith("AP")) return env.APAC_BACKEND;
  return env.US_BACKEND;  // default
}

resource "aws_route53_record" "llm_canary" {
  zone_id        = var.zone_id
  name           = "api.example.com"
  type           = "A"
  set_identifier = "canary-eu-new-model"

  weighted_routing_policy {
    weight = 5   # 5% traffic to new model in EU
  }

  alias {
    name    = aws_lb.eu_canary.dns_name
    zone_id = aws_lb.eu_canary.zone_id
    evaluate_target_health = true
  }
}

resource "aws_s3_bucket_replication_configuration" "model_weights" {
  bucket = aws_s3_bucket.models_us.id
  role   = aws_iam_role.replication.arn

  rule {
    id     = "replicate-models"
    status = "Enabled"

    destination {
      bucket        = aws_s3_bucket.models_eu.arn
      storage_class = "STANDARD"
    }
  }
}

# health.py — runs inside each vLLM pod as a sidecar or within the container
from fastapi import FastAPI
import httpx, asyncio

app = FastAPI()
VLLM_BASE = "http://localhost:8000"

@app.get("/health")
async def health():
    try:
        r = await httpx.AsyncClient(timeout=10).post(
            f"{VLLM_BASE}/v1/completions",
            json={"model": "llama-3-70b", "prompt": "1+1=", "max_tokens": 1},
        )
        r.raise_for_status()
        return {"status": "ok"}
    except Exception as e:
        raise HTTPException(503, detail=str(e))

# Route 53 geolocation record — EU users always land in eu-west-1
resource "aws_route53_record" "llm_gdpr" {
  zone_id        = var.zone_id
  name           = "api.example.com"
  type           = "A"
  set_identifier = "eu-geo"

  geolocation_routing_policy {
    continent = "EU"
  }

  alias {
    name                   = aws_lb.eu.dns_name
    zone_id                = aws_lb.eu.zone_id
    evaluate_target_health = false   # do NOT failover to non-EU on outage
  }
}
